                <button
                  key={value}
                  type="button"
                  onClick={() => toggleAmenity(value)}
                  className={`p-3 rounded-xl border transition-all flex flex-col items-center gap-1 ${
                    localForm.amenities.includes(value)
                      ? 'bg-cyan-500/20 border-cyan-500/50 text-cyan-400'
